var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"……천사님.","JPN":"……天使様。","ENG":"...Angel.","TWN":"……天使。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_1"},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면 천사님이 하신 말씀이 사실일지도 몰라요.","JPN":"もしかしたら天使様の話が本当なのかもしれません。","ENG":"Maybe what you said was right after all.","TWN":"也許天使說的話是真的。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_2"},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"과연, 그렇군요…….","JPN":"なるほど、そういうことですか……","ENG":"Oh, I see...","TWN":"果然，原來如此……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 무장과 날개는 기계 장치의 마왕… 그 소체를 모방한 건가요?","JPN":"その武装や翼は機械装置の魔王……その構造を真似たのですか？","ENG":"Those armaments and wings... Are they modeled after the Demon Lord of Machinery?","TWN":"那武裝和翅膀是機械裝置的魔王……是模仿了那個軀體嗎？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"맞아요. 천사님의 모습을 잠시 빌렸어요.","JPN":"そうです。ちょっとだけ天使様の姿を借りました。","ENG":"Yeah. I borrowed the angel's form for a bit.","TWN":"沒錯。我暫時借用了天使的模樣。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"당신 말대로, 저는 무엇 하나 가지지 못한 가짜에 불과하지만…….","JPN":"あなたの言う通り、私は何一つ持っていない偽物ですけど……","ENG":"Like you said, I don't really have anything of my own...","TWN":"如你所說，我不過是個一無所有的冒牌貨……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"반대로 그 무엇이든 될 수 있으니까요.","JPN":"だからこそ、何にだってなれます。","ENG":"But that means I can become anything.","TWN":"但相反，我也可以成為任何東西。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시 당신은 저와 닮은 꼴이로군요, 세피라의 화신.","JPN":"やはりあなたは私に似ています、セフィラの化身。","ENG":"You really are like me, Personification of Sephira.","TWN":"果然你和我很相似啊，生命樹的化身。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_02"},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세계를 재구성할 신성에 다다랐으면서도, 마지막까지 자신이 아닌 타인의 것을 모방하다니.","JPN":"世界を再構成できる程の神聖に至っておきながら、最後まで自分ではない他人のものを模倣するとは。","ENG":"You reached the threshold of Divinity, yet even now, you're still imitating others.","TWN":"即便達到了能夠重構世界的神性，最後仍然模仿他人而非自我。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이래서야 저나 당신이나 결국 운명의 꼭두각시 신세로군요.","JPN":"これでは、私もあなたも運命の操り人形にすぎませんね。","ENG":"In the end, we're both just puppets of fate.","TWN":"看來我和你最終都是命運的傀儡啊。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"narration","speaker":null,"text":{"KOREA":"이 세상의 모든 것은, 마치 거대하고 차가운 기계처럼.","JPN":"この世界のすべては、まるで巨大で冷たい機械のように。","ENG":"Everything in this world feels like one giant, cold machine.","TWN":"這個世界上的一切，就像一台巨大而冰冷的機器。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_3"},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"세계를 만드는 법칙에 의해, 전부 정해져 있던 걸지도 모른다고.","JPN":"世界を作る法則によって、全部決まっていたのかもしれないって。","ENG":"Maybe everything was already decided by the law of creating a world.","TWN":"也許一切都已經被創造世界的法則所決定了。"},"stage":{"bg":"BLACK","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_4"},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"아니요. 저는 인간이에요.","JPN":"いいえ、私は人間です。","ENG":"No. I'm human.","TWN":"不，我是人類。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"인간은 누구나 다른 사람에게 도움을 받고 살아요.","JPN":"人間は誰だって、他の人に助けられながら生きています。","ENG":"And humans live with help from others.","TWN":"人類無論是誰，都是依靠他人的幫助而生活的。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"힘들 때는 손을 내밀어도 괜찮아요. 그건 부끄러운 게 아니니까요.","JPN":"辛い時は手を伸ばしても大丈夫です。それは恥ずかしいことじゃありません。","ENG":"It's okay to reach out when you're struggling. There's nothing shameful about that.","TWN":"困難的時候，伸出手來求助也沒關係。這並不是什麼？恥的事情。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"대신, 도움을 받았다면 언젠가 그 도움을 돌려줄 수 있어야 해요.","JPN":"その代わり、助けてもらったのなら、いつかそれを返せるようにならないといけないんです。","ENG":"But if you receive help, you have to return it someday.","TWN":"相應的，如果得到了幫助，總有一天也要回報這份幫助。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"미나 선배, 에이미 씨, 펠리세트와 라이카… 모두 저를 구하기 위해 여기까지 와주었어요.","JPN":"ミナ先輩、エイミーさん、フェリセットとライカ……みんな私を助けるためにここまで来てくれました。","ENG":"Mina, Amy, Félicette, and Laika... they all came here to save me.","TWN":"米娜前輩，艾米，費莉塞特和萊卡……大家都是為了救我才來到這裡的。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"그러니까 저도 그 도움에 반드시 보답하고 싶어요.","JPN":"だから私も絶対、それを返したいです。","ENG":"So I want to repay them.","TWN":"所以，我也一定想要回報那份幫助。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"그런 게 바로 <color=#ffd34c>인연</color>일 테니까.","JPN":"それが<color=#ffd34c>絆</color>でしょうから。","ENG":"That's what a <color=#ffd34c>bond</color> is.","TWN":"那就是所謂的<color=#ffd34c>緣分</color>吧。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"물러서, 스완!","JPN":"下がれ、スワン！","ENG":"Back off, Swan!","TWN":"退後，史旺！"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"두 번 다시 노엘에게 접근하게 두지 않을 테니까……!","JPN":"二度とノエルには近づけさせない……！","ENG":"I won't let you get anywhere near Noelle again...!","TWN":"我絕不會再讓你接近洛艾兒！"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"큭…! 제법 끈질기군요 늑대……!","JPN":"くっ……！　なかなかしぶといですね、オオカミ……！","ENG":"Kgh...! Still clinging on, Wolf...?!","TWN":"咳！你還真是頑強呢，狼……！"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 스완! 지금 어딜 보는 거야……?","JPN":"おい、スワン！　どこ見てんだよ！","ENG":"Hey, Swan! Look at me...!","TWN":"喂，史旺！？現在在看哪裡？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"방심하지 말라고……!","JPN":"油断は禁物でしょ……！","ENG":"Don't let your guard down...!","TWN":"我說了不要掉以輕心！"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"퍼스트윙……!","JPN":"ファーストウイング……！","ENG":"Firstwing...!","TWN":"弗斯特薇！"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"내가 말했지? 그 잘난 낯짝에 꼭 한 방 먹여 줄 거라고……!","JPN":"あたし言ったよね？　その綺麗な面に、絶対一発食らわせてやるって……！","ENG":"Told you, didn't I? I was gonna land one clean hit on that smug face of yours...!","TWN":"我說過吧？一定要給那張自以為是的臉來一拳！"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어때? 아무래도 그때가 온 것 같은데?","JPN":"ほら、どうやらその時が来たみたいだけど！","ENG":"And I think now's the perfect time!","TWN":"怎麼樣？看來那個時候到了吧？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요…! 리트리버 주제에 제법 꿈이 큰 것 같네요……!","JPN":"どうでしょう……！　レトリーバーの分際で大層な夢ですね……！","ENG":"Well...! Looks like the retriever's dreaming big today...!","TWN":"哎呀！身為一隻獵犬，你的夢想還真不小呢……！"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"어이, 여배우! 이쪽도 잊으면 섭섭한데 말이야!","JPN":"おい、女優さんよ！　こっちも忘れてもらっちゃ困るんだよな！","ENG":"Hey, actress! You didn't forget about us, did you?!","TWN":"喂，女演員！要是忘了我這邊，可就太讓人傷心了！"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L2_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"방심하지 말아요, 라이카.","JPN":"油断しないでね、ライカ。","ENG":"Stay sharp, Laika.","TWN":"不要掉以輕心，萊卡。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"상대는 스완이에요. 또 무슨 수를 숨기고 있을지 몰라요.","JPN":"相手はスワンよ、また何か隠し持っているのかも。","ENG":"This is Swan we're dealing with. Who knows what tricks she's still hiding.","TWN":"對手是史旺。不知道她還藏著什麼手段。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"모두들…….","JPN":"みなさん……","ENG":"Everyone...","TWN":"各位……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"고마워요, 이런 저를 끝까지 믿어주어서…….","JPN":"ありがとうございます、こんな私を最後まで信じてくれて……","ENG":"Thank you. For believing in me all the way to the end...","TWN":"謝謝你，一直相信這樣的我……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"그러니까…….","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"미나 선배와의 만남도…….","JPN":"ミナ先輩との出会いも……","ENG":"Meeting Mina...","TWN":"和米娜前輩的相遇也是……"},"stage":{"bg":"SP_001","bgm":"THEMA_CA_INTERN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_5"},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"그리고 제가 가진 모든 것들이 사실은 모두 가짜였다는 것도…….","JPN":"そして、私の大事なものすべてが、実は偽物だったということも……","ENG":"And learning that everything I had was actually fake...","TWN":"我所擁有的一切其實都是假的……"},"stage":{"bg":"CHARADE2_05","bgm":"THEMA_CA_INTERN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_6"},{"id":"L18_1","type":"narration","speaker":null,"text":{"KOREA":"어쩌면 천사님의 말씀대로, 처음부터 전부 정해진 것일지도 몰라요.","JPN":"もしかしたら天使様の言うとおり、最初から全部決まっていたのかもしれません。","ENG":"Maybe just like you said, angel, everything really was decided from the start.","TWN":"或許，正如天使所說，從一開始就已經全部註定了。"},"stage":{"bg":"QLIPHOTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_7"},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 역시 재밌군요.","JPN":"ふふ、やはり面白いですね。","ENG":"Haha, you really are interesting.","TWN":"呵呵，果然有趣啊。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 이곳은 저만의 클리파 영역, 기억의 극장.","JPN":"ですがここは私だけのクリファ領域、記憶の劇場。","ENG":"But this place is my Qlipha domain, the Theater of Memories.","TWN":"但這裡是我獨有的逆卡巴拉領域，記憶的劇場。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 극장에서 당신들은 결코 저를 쓰러트릴 수 없습니다.","JPN":"この劇場では、決してあなたたちは私を倒すことができません。","ENG":"And in this theater, none of you can defeat me.","TWN":"在這個劇場裡，你們絕對無法打倒我。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어째서……?","JPN":"どうして……？","ENG":"How...?","TWN":"為什麼？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어째서 거울상이……?","JPN":"どうして鏡像が……？","ENG":"How the mirror image...?","TWN":"為什麼鏡像會？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"틀렸어요, 스완.","JPN":"違います、スワン。","ENG":"You're wrong, Swan.","TWN":"你錯了，史旺。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"당신은 이길 수 없어요.","JPN":"あなたは勝てません。","ENG":"You can't win.","TWN":"你贏不了的。"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세피라의… 화신……?","JPN":"セフィラの……化身……？","ENG":"Personification... of Sephira...?","TWN":"生命樹的……化身？"},"stage":{"bg":"MIND_FILM","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"그렇지만… 저, 이제는 도망치지 않을 거예요.","JPN":"でも……私、もう逃げませんよ。","ENG":"But even so... I'm not going to run anymore.","TWN":"可是……我現在不會再逃跑了。"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_8"},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"도망치지 않고 똑바로 생각할 거예요.","JPN":"逃げないで、ちゃんと考えます。","ENG":"I'll face it. I'll think it through.","TWN":"我會認真思考，不會逃避。"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_9"},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"제가 정말로 원하는 게 무엇인지.","JPN":"私が本当に望むものは何なのか。","ENG":"What I truly want.","TWN":"我真正想要的是什麼？"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_10"},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"제가 이곳에 존재하는 이유가 무엇인지를……!","JPN":"私がここに存在している理由は何なのかを……！","ENG":"Why I exist in this world...!","TWN":"我存在於此的理由是什麼？"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_11"},{"id":"L39_1","type":"narration","speaker":null,"text":{"KOREA":"그러니까……!","JPN":"だから……！","ENG":"So...!","TWN":"所以！"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_12"},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"명과 암, 질서와 혼돈 그리고 창조와 소멸…….","JPN":"明と暗、秩序と混沌、そして創造と消滅……","ENG":"Light and shadow, order and chaos, creation and destruction...","TWN":"光明與黑暗，秩序與混沌，以及創造與毀滅……"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"클리파 허수 에너지와 세피라 신성 에너지는 마치 동전의 앞면과 뒷면 같은 힘이에요.","JPN":"クリファ虚数エネルギーとセフィラ神聖エネルギーは、まるでコインの裏表のような力です。","ENG":"Qlipha Imaginary Energy and Sephira Divinity Energy are two sides of the same coin.","TWN":"逆卡巴拉虛數能量和生命樹神聖能量，就像硬幣的正反兩面一樣的力量。"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"따라서 당신이 클리파 허수 에너지를 통해, 자신의 심상을 반영한 클리파 영역을 만들었듯.","JPN":"だからあなたがクリファ虚数エネルギーを使って、自分の心象を反映したクリファ領域を作ったように、","ENG":"Just as you used the Qlipha Imaginary Energy to shape a domain that reflected your will.","TWN":"因此，就像你通過逆卡巴拉虛空能量創造了反映自己心象的逆卡巴拉領域一樣。"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"저는 이 영역의 힘을 역전시켜서, 저만의 <color=#ffd34c>세계</color>를 만들었습니다.","JPN":"私はこの領域の力を逆転させて、私だけの<color=#ffd34c>世界</color>を作りました。","ENG":"I inverted that domain and created a <color=#ffd34c>world</color> of my own.","TWN":"我逆轉了這個領域的力量，創造了屬於我的<color=#ffd34c>世界</color>。"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세피라 신성 에너지…….","JPN":"セフィラ神聖エネルギー……","ENG":"Sephira Divinity Energy...","TWN":"生命樹神聖能量……"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇다면, 이 순간이야말로 이 땅에 천사가 강림하는 순간이겠군요.","JPN":"でしたら、この瞬間こそがこの地に天使が降臨する瞬間なのでしょうね。","ENG":"Then this really is the moment an angel descends upon this land.","TWN":"那麼，這一刻就是天使降臨這片土地的時刻了。"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"스완…….","JPN":"スワン……","ENG":"Swan...","TWN":"史旺……"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"지금부터 당신에게 그 세계를 보여드릴게요.","JPN":"今からあなたにその世界を見せてあげます。","ENG":"Now I'll show you my world.","TWN":"現在我將向你展示那個世界。"},"stage":{"bg":"MS_1402","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"스완의 클리파 영역이 순식간에 사라졌어……!","JPN":"スワンのクリファ領域が一瞬で消えた……！","ENG":"Swan's Qlipha domain just vanished in an instant...!","TWN":"史旺的逆卡巴拉領域瞬間消失了！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이 세계는 대체……?","JPN":"この世界はいったい……？","ENG":"What is this place...?","TWN":"這個世界到底是？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 풍경은…? 이 세계를 정말로 노엘이 만들어 냈다고……?","JPN":"この風景は……？　この世界を本当にノエルが作り出したの……？","ENG":"This scenery...? Did Noelle really create all this...?","TWN":"這風景是?這個世界真的是洛艾兒創造出來的嗎？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 풍경은… 틀림없이 <color=#ffd34c>금빛 새벽</color>…….","JPN":"この風景は……間違いない。<color=#ffd34c>金色の暁</color>……","ENG":"This landscape... It's unmistakable. It's the <color=#ffd34c>golden dawn</color>...","TWN":"這風景……無疑是<color=#ffd34c>金色黎明</color>……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"무수히 갈리진 모든 평행 세계… 그 태초의 풍경…….","JPN":"無数に分かれた全てのパラレルワールド……その始まりの風景……","ENG":"The very first view, before all the worlds splintered into countless parallel paths...","TWN":"無數分裂的所有平行世界……那最初的風景……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"태초의 풍경……?","JPN":"始まりの風景……？","ENG":"The first view...?","TWN":"最初的風景？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"그럼, 지금 우리가 보고 있는 풍경이 세계가 시작되는 순간이라고?","JPN":"じゃあ、私たちが見ているこの風景が、世界が始まる瞬間だってこと？","ENG":"You're telling me this is what the world looked like when it first began?","TWN":"那麼，我們現在看到的景象就是世界開始的瞬間嗎？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"……스완.","JPN":"……スワン。","ENG":"...Swan.","TWN":"……史旺。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"제가 만든 작은 세계에서, 제가 규정한 법칙은 단 <color=#ffd34c>하나</color> 뿐이에요.","JPN":"私が作った小さな世界で、私が定めた法則はたった<color=#ffd34c>一つ</color>だけです。","ENG":"In the world I created, there's only <color=#ffd34c>one</color> law.","TWN":"在我創造的小世界中，我制定的法則只有<color=#ffd34c>一個</color>。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"<color=#ffd34c>스완, 당신은 결코 승리에 다다를 수 없어요.</color>","JPN":"<color=#ffd34c>スワン、あなたは決して勝利にたどり着けません。</color>","ENG":"<color=#ffd34c>Swan, you can never achieve victory.</color>","TWN":"<color=#ffd34c>史旺，你絕對無法獲得勝利。</color>"},"stage":{"bg":"SKY","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"당신이 그 어떤 능력을 쓰든, 당신이 그 어떤 권모술수를 부리든…….","JPN":"あなたがどんな能力を使っても、どんな計略を図っても……","ENG":"No matter what power you use, no matter what schemes you come up with...","TWN":"無論你使用什麼能力，無論你耍什麼？謀詭計……"},"stage":{"bg":"SKY","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"이 세계 안에서 당신은 그 누구에게도, 그 무엇으로도 이길 수 없어요.","JPN":"この世界の中では、あなたは誰にも、何をしても勝てません。","ENG":"In this world, you can't win against anyone or anything.","TWN":"在這個世界裡，你無法戰勝任何人或任何事物。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"그러니까 인정하세요, 스완.","JPN":"だから認めてください、スワン。","ENG":"So admit it, Swan.","TWN":"所以承認吧，史旺。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"당신의 패배를.","JPN":"あなたの負けを。","ENG":"Admit your defeat.","TWN":"你的失敗。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_INTERN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후후…….","JPN":"ふふふ……","ENG":"Hahaha...","TWN":"呵呵呵……"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 과연 그럴까요?","JPN":"果たしてそうでしょうか？","ENG":"Well, we will see about that.","TWN":"這個嘛，真的會這樣嗎？"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"제길, 스완…! 또 무슨 짓을 꾸미려는 거야……!","JPN":"くそ、スワン……！　また何を企んでいる……！","ENG":"Damn it, Swan...! What are you scheming now...?!","TWN":"該死，史旺！你想做什麼……！"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이제 그만하고 좀 포기하라고……!","JPN":"もういい加減諦めなって……！","ENG":"Just give it up already...!","TWN":"我說夠了，放棄吧！"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"미나 선배……!","JPN":"ミナ先輩……！","ENG":"Mina...!","TWN":"米娜前輩！"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"모든 것은 각본대로.","JPN":"すべては脚本どおりに。","ENG":"Everything according to the script.","TWN":"一切都將按照劇本進行。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_34"},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"그건 무척이나, 오래된 다짐.","JPN":"それはとても古い誓い。","ENG":"That is my old determination.","TWN":"那是非常久遠的誓言。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_35"},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"그 각본 끝에 어떤 결말이 기다리고 있다 하더라도.","JPN":"その脚本の終わりにどんな結末が待っていようと……","ENG":"No matter what ending awaits me at the end of it.","TWN":"即使在那個劇本的結尾，等待我的是某種結局。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_36"},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"모든 것을 처음으로 되돌리기 위해서라면, 어떤 배역이라도 받아들이겠다는 선택.","JPN":"すべてを振り出しに戻すためなら、どんな配役でも受け入れる。","ENG":"A choice I made to accept any role if it meant reverting everything to the beginning.","TWN":"為了將一切恢復原狀，我願意接受任何角色。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_37"},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"그래, 이 이야기는 아마도 여기서 끝을 내는 편이 좋겠지.","JPN":"そう、おそらくこの物語はここで終わりにした方がいいだろう。","ENG":"Yes, this story should probably end here.","TWN":"嗯，這個故事可能就到這裡結束比較好吧。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_38"},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후…….","JPN":"ふふ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_39"},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"역시… 나는 틀리지 않았어…….","JPN":"やはり……私は間違っていなかった……","ENG":"I knew it... I wasn't wrong...","TWN":"果然……沒有錯……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_40"},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 이야기를… 처음으로 되돌리기 위해서는…….","JPN":"全ての物語を……振り出しに戻すためには……","ENG":"To revert all the stories... to their beginning...","TWN":"為了讓整個故事回到起點……"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_41"},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"커흑……!!","JPN":"がはっ……！！","ENG":"Kuh...!!","TWN":"唔……！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE","voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_42"},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"피하지… 않았어……?","JPN":"避け……なかった……？","ENG":"She... didn't dodge it...?","TWN":"沒有躲開？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아니, 오히려…….","JPN":"いや、むしろ……","ENG":"No, it's as if...","TWN":"不，反而……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff...!*","TWN":"哈啊，哈啊，哈啊…！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세피라의 화신…! 대체 무슨 짓을 한 거죠……?","JPN":"セフィラの化身……！　いったい何の真似ですか……？","ENG":"Personification of Sephira...! What did you do to me...?","TWN":"生命樹的化身！？到底做了什麼？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"크윽, 어째서…….","JPN":"くうっ、どうして……","ENG":"Kgh, why...?","TWN":"咳，為什麼……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"스완.","JPN":"スワン。","ENG":"Swan.","TWN":"史旺。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"이제 그만하세요.","JPN":"もうやめましょう。","ENG":"It's over.","TWN":"請到此為止吧。"},"stage":{"bg":"SKY","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……큭.","JPN":"……くっ。","ENG":"...Kgh.","TWN":"……咳。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하아… 하아… 하아…….","JPN":"はぁ……はぁ……はぁ……","ENG":"*Huff...* *Huff...* *Huff...*","TWN":"哈啊……哈啊……哈啊……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요. 언젠가 말씀드렸을 텐데요, 노엘 라이트.","JPN":"それはどうでしょう。いつか言ったはずです、ノエル・ライト。","ENG":"Well. I think I told you before, Noelle Wright.","TWN":"嗯……我想我曾經告訴過你，洛艾兒·萊特。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 같잖은 마음으로 악역을 동정하지 말라고.","JPN":"その生温い気持ちで悪役に同情なんてしないで、と。","ENG":"To save your worthless sympathy for someone else.","TWN":"別用那可笑的心態去同情反派。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"그래요, 인정하겠습니다.","JPN":"そうですね、認めましょう。","ENG":"Fine. I admit it.","TWN":"好吧，我承認。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"이 세계에서는 당신들을 이길 수 없어요. 제 패배입니다.","JPN":"この世界では、あなたたちに勝つことは叶いません。私の負けです。","ENG":"I can't win in this world. You've defeated me.","TWN":"在這個世界上，我無法戰勝你們。我輸了。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"하지만 악역을 동정해버린 당신들의 패배기도 하죠.","JPN":"ですが悪役に同情してしまった、あなたたちの負けでもあります。","ENG":"But by pitying the villain, you've lost too.","TWN":"但同情反派的你們也算是失敗了。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_SEAWAVE"},{"id":"L30_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"제기랄! 무슨 개소리야!","JPN":"くそ！　妙な真似すんじゃねー！","ENG":"Damn it! The heck is she on about?!","TWN":"可惡！？在說什麼鬼話啊！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마…! 아까 그건 속임수였나……?","JPN":"まさか……！　さっきのあれはフェイクだったの……？","ENG":"Wait...! Was that all a trick...?","TWN":"難道！剛才那是騙人的把戲嗎？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"다들 보고만 있을 거야? 저 망할 년이 거울로 도망치잖아……!","JPN":"みんな、指くわえて見てるつもり？　クソ女が鏡に逃げて行くのに……！","ENG":"Are you all just gonna stand there!? That damn woman's escaping into the mirror...!","TWN":"大家就只會看著嗎？那個該死的女人要通過鏡子逃跑了！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘……!","JPN":"ノエル……！","ENG":"Noelle...!","TWN":"洛艾兒！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐, 노엘의 모습이 원래대로 돌아왔잖아……?","JPN":"あれ？　ノエルの姿が元に戻った……？","ENG":"Wait, she's changing back to herself...?","TWN":"等等，洛艾兒的樣子恢復原樣了？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배…….","JPN":"ミナ先輩……","ENG":"Mina...","TWN":"米娜前輩……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘, 너 괜찮아?","JPN":"ノエル、大丈夫？","ENG":"Noelle, are you okay?","TWN":"洛艾兒，你沒事吧？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아마도 이 세계를 만들기 위해 상당한 힘을 소진한 모양이로군요.","JPN":"おそらくこの世界を作るために、相当な力を使ったのでしょう。","ENG":"Looks like she used up most of her power creating that world.","TWN":"看來為了創造這個世界，耗費了相當大的力量呢。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋은 배우는 박수 칠 때 떠나는 법이죠.","JPN":"いい俳優は、拍手が鳴りやむ前に舞台を降りるものです。","ENG":"A good actress always leaves at the final curtain.","TWN":"優秀的演員懂得在掌聲中離開。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"커튼 콜은 여기까지.","JPN":"カーテンコールはここまで。","ENG":"Curtain call's over.","TWN":"謝幕演出到此結束。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼, 부디 다음 무대에서 뵐 수 있기를…….","JPN":"では、どうか次の舞台でお会いしましょう……","ENG":"Let's meet again, on the next stage...","TWN":"那麼，希望能在下一個舞台上見到你……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_CA_SWAN_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LAIKA_SPACESUIT_NULL_NULL","text":{"KOREA":"빌어먹을! 거기 안 서……!","JPN":"くそ！　待ちやがれ……！","ENG":"Damn it! Get back here...!","TWN":"該死！想跑！？"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"FELICETTE_SPACESUIT_NULL_NULL","text":{"KOREA":"소용없어요, 라이카. 이미 거울로 도망쳤어.","JPN":"無駄よ、ライカ。　もう鏡に逃げてしまったわ。","ENG":"It's no use, Laika. She already escaped through the mirror.","TWN":"沒用的，萊卡。已經逃到鏡子裡去了。"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_SPACESUIT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_SPACESUIT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"야, 노엘! 눈 좀 떠봐……!","JPN":"ちょっと、ノエル！　目を覚まして……！","ENG":"Hey! Noelle, wake up...!","TWN":"喂，洛艾兒！睜開眼睛！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이제 다 끝났어. 다 끝났다고……!","JPN":"全部終わった。終わったんだ……！","ENG":"It's over. It's all over now...!","TWN":"現在全都結束了。都結束了！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배……?","JPN":"ミナ先輩……？","ENG":"Mina...?","TWN":"米娜前輩？"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘……!","JPN":"ノエル……！","ENG":"Noelle...!","TWN":"洛艾兒！"},"stage":{"bg":"SEPHIROTH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배! 미나 선배다……!","JPN":"ミナ先輩！　ミナ先輩だ……！","ENG":"Mina! It's you...!","TWN":"米娜前輩！米娜前輩！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"좋은 아침이에요! 보고 싶었어요, 선배!","JPN":"おはようございます！　会いたかったです、先輩！","ENG":"Good morning! I missed you so much!","TWN":"早安！我好想你，前輩！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"극장에서 스크린으로 선배를 계속 보고 있었지만, 그래도 또 보고 싶었어요!","JPN":"劇場でスクリーン越しにずっと先輩を見ていたけど、それでも会いたかったです！","ENG":"I kept watching you on the theater screen, but it wasn't the same!","TWN":"雖然在電影院裡一直盯著螢幕上的前輩看，但還是想再看一次！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이렇게 진짜로 보니까 정말 좋다. 이히히.","JPN":"こうやって直接会えて、本当に嬉しいです。えへへ。","ENG":"Seeing you in real life again is the best! Ehehe!","TWN":"這樣真的看到，真好。嘻嘻。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고생 많았어, 노엘.","JPN":"お疲れ様、ノエル。","ENG":"You did great, Noelle.","TWN":"辛苦了，洛艾兒。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그리고 나도 널 보고 싶었어.","JPN":"それから、私も会いたかったよ。","ENG":"And I missed you too.","TWN":"而且我也想見你。"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우오옷…! 정말이에요……?","JPN":"ぬぅおっ……！　本当ですか……？","ENG":"Ooh...! Really...?","TWN":"噢噢噢！真的是這樣嗎？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배가 절 보고 싶어 했다니, 너무너무 기뻐요!","JPN":"ミナ先輩にそう思ってもらえるなんて、嬉しすぎます！","ENG":"You missed me? That makes me so, so happy!","TWN":"米娜前輩想見我，真是太開心了！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"얼만큼! 얼만큼 보고싶었나요……?","JPN":"どのくらい？　どのくらい会いたかったですか……？","ENG":"How much? How much did you miss me...?","TWN":"有多麼！有多麼想見我呢？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어, 얼만큼……?","JPN":"ど、どのくらい……？","ENG":"H-how much...?","TWN":"要，要多少？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네…! 하늘만큼…? 땅만큼……?","JPN":"はい……！　果てしない空くらい……？　水平線向こうの大地くらい……？","ENG":"Yes...! As much as heaven and earth...?","TWN":"是！像天空一樣？還是像大地一樣？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그것도 아니라면… 허걱! 설마 초속 73km 메가파섹으로 가속 팽창하는 우주만큼……!?","JPN":"それとも……ハッ！　まさか1メガパーセクごとに秒速73kmで加速膨張する宇宙くらい……！？","ENG":"Or maybe... like the universe expanding at seventy-three kilometers per megaparsec...?!","TWN":"如果不是這樣的話……哎呀！難道是以每秒73公里的速度加速膨脹的宇宙一樣！？"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 비유가 이상하잖아……!","JPN":"な、何それ？　例えがおかしくない……！？","ENG":"W-what? That's not even a real comparison...!","TWN":"怎、怎麼回事？比喻不對勁啊！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"크흠, 아무튼 그 정도는 아니라고!","JPN":"こほん、とにかくそれ程じゃないから！","ENG":"Ahem, definitely not that much!","TWN":"咳咳，總之不是那樣的！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아하핫! 괜찮아요! 제가 그만큼 보고 싶었으니까!","JPN":"あははっ！　大丈夫です！　私がそれくらい会いたかったので！","ENG":"Ahaha! That's okay! Because I missed you enough for both of us!","TWN":"啊哈哈哈哈！沒關係！因為我也很想見到你！"},"stage":{"bg":"SEPHIROTH","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배.","JPN":"ミナ先輩。","ENG":"Mina.","TWN":"米娜前輩"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저… 사실 선배한테 줄곧 하고 싶은 말이 있었어요…….","JPN":"実は……私、先輩にずっと伝えたかったことがあるんです……","ENG":"There's something I've always wanted to tell you...","TWN":"我……其實一直有話想對前輩說……"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 무슨 말인데?","JPN":"え？　何？","ENG":"Hmm? What is it?","TWN":"嗯？什麼話？"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"우으으… 그건 말이죠…….","JPN":"ううぅ……それはですね……","ENG":"Um... Well...","TWN":"嗚嗚嗚……其實是這樣的……"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"고마워요, 미나 선배.","JPN":"ありがとうございます、ミナ先輩。","ENG":"Thank you, Mina.","TWN":"謝謝你，米娜前輩。"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_18"},{"id":"L49_1","type":"narration","speaker":null,"text":{"KOREA":"선배와의 소중한 인연을 통해서… 비로소 깨달을 수 있었어요.","JPN":"先輩との大切な絆が……私に気付かせてくれました。","ENG":"Thanks to your bond... I finally understand.","TWN":"通過與前輩的珍貴緣分……我終於領悟到了。"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_19"},{"id":"L50_1","type":"narration","speaker":null,"text":{"KOREA":"저, 선배에게 힘이 되어주고 싶어요.","JPN":"私、先輩の力になりたい。","ENG":"I want to be someone who gives you strength.","TWN":"我想成為前輩的力量。"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_20"},{"id":"L1_1","type":"narration","speaker":null,"text":{"KOREA":"앞으로도 선배의 곁에 계속 머물고 싶어요.","JPN":"これからも先輩のそばにずっといたいです。","ENG":"I want to stay by your side from now on.","TWN":"今後我也想一直待在前輩身邊。"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_21"},{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"결국 언젠가 그 끝이 올지도 모르지만…….","JPN":"結局いつかは終わりが来るのかもしれませんけど……","ENG":"Even if everything ends someday...","TWN":"最終可能有一天會迎來終結……"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_22"},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 왜 이렇게 뜸을 들이는 거야?","JPN":"なに、そんなに勿体ぶってどうしたの？","ENG":"Why the long pause?","TWN":"怎麼了，為什麼這麼磨蹭？"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"중요한 이야기야?","JPN":"大事な話？","ENG":"Is it something important?","TWN":"重要的事情嗎？"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"좋아해요.","JPN":"好きです。","ENG":"I like you.","TWN":"喜歡你。"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_23"},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"미나 선배.","JPN":"ミナ先輩。","ENG":"Mina.","TWN":"米娜前輩。"},"stage":{"bg":"MS_1406","bgm":"THEMA_MEMORY_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_FENRIR_CA_INTERN_IN_TRAILER_24"}]`);export{e as default};